import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    distances = []
    wait_times = []

    for customer_pos in unvisited_customers:
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos) / truck_speed
        distances.append(distance_to_customer)

    min_total_time = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        if current_time + distances[i] <= time_windows[i][1]:
            total_time = max(current_time + distances[i], time_windows[i][0]) + distances[i]
            if total_time < min_total_time:
                min_total_time = total_time
                best_node = i
        else:
            wait_time = current_time + distances[i] - time_windows[i][1]
            total_time = time_windows[i][0] + wait_time
            if total_time < min_total_time:
                min_total_time = total_time
                best_node = i

    return best_node
